     1→/**
     2→ * Audit Trail Generator - Hybrid Progressive Recording
     3→ *
     4→ * Implements the hybrid approach from AUDIT_TRAIL_PLAN.md:
     5→ * - Progressive recording: Call recordStage() after EACH stage completes
     6→ * - Partial trace resilience: If pipeline crashes at stage 5, stages 1-4 are already recorded
     7→ * - Final aggregation: Call finalize() after all stages complete for validation and summary
     8→ * - Failure context: Call recordFailure() if pipeline crashes to add error details
     9→ *
    10→ * This approach combines the benefits of incremental mutation (partial traces on failure)
    11→ * with the benefits of end aggregation (clean separation of concerns, validation).
    12→ */
    13→
    14→import { ClassificationResult } from '../types/classification-result';
    15→import { ClassificationSession } from '../types/classification-session';
    16→import { CategoryConfiguration } from '../types/category-configuration';
    17→import { StageName, PIPELINE_STAGE_ORDER } from '../types/stage-name';
    18→import {
    19→  HardAssertionResult,
    20→  StrongIndicatorResult,
    21→  CategoryRuleResult,
    22→  AttributeDetectionResult,
    23→  AttributeInfluenceResult,
    24→  DisambiguationResult,
    25→  MultiLabelResult,
    26→  AIRoutingResult,
    27→} from '../types/explainability-trace';
    28→
    29→/**
    30→ * Audit Trail Generator Class
    31→ *
    32→ * Progressively records stage results into explainability trace
    33→ * with final aggregation and validation.
    34→ */
    35→export class AuditTrailGenerator {
    36→  private readonly config: CategoryConfiguration;
    37→
    38→  constructor(config: CategoryConfiguration) {
    39→    this.config = config;
    40→  }
    41→
    42→  /**
    43→   * Record a single stage's results into the explainability trace
    44→   *
    45→   * Called by pipeline after EACH stage completes.
    46→   * Updates result.explainabilityTrace progressively.
    47→   *
    48→   * @param stageName - Name of the stage that just completed
    49→   * @param result - Classification result (mutated in place)
    50→   * @param session - Classification session context
    51→   */
    52→  recordStage(stageName: StageName, result: ClassificationResult, _session: ClassificationSession): void {
    53→    // Extract stage-specific data from result fields
    54→    const stageData = this.extractStageData(stageName, result);
    55→
    56→    // Update explainability trace with stage results
    57→    switch (stageName) {
    58→      case 'hardAssertions':
    59→        result.explainabilityTrace.hardAssertions = stageData as HardAssertionResult[];
    60→        result.explainabilityTrace.configurationRefs['hardAssertions'] = 'categorySignals.*.hardAssertions';
    61→        break;
    62→
    63→      case 'strongIndicators':
    64→        result.explainabilityTrace.strongIndicators = stageData as StrongIndicatorResult[];
    65→        result.explainabilityTrace.configurationRefs['strongIndicators'] = 'categorySignals.*.strongIndicators';
    66→        break;
    67→
    68→      case 'ruleScoring':
    69→        result.explainabilityTrace.ruleScoring = stageData as CategoryRuleResult[];
    70→        result.explainabilityTrace.configurationRefs['ruleScoring'] = 'categorySignals.*.subtypes';
    71→        break;
    72→
    73→      case 'attributeDetection':
    74→        result.explainabilityTrace.attributeDetection = stageData as AttributeDetectionResult[];
    75→        result.explainabilityTrace.configurationRefs['attributeDetection'] = 'attributes';
    76→        break;
    77→
    78→      case 'attributeInfluence':
    79→        result.explainabilityTrace.attributeInfluence = stageData as AttributeInfluenceResult[];
    80→        result.explainabilityTrace.configurationRefs['attributeInfluence'] = 'categorySignals.*.attributeRelevance';
    81→        break;
    82→
    83→      case 'disambiguation':
    84→        result.explainabilityTrace.disambiguation = stageData as DisambiguationResult[];
    85→        result.explainabilityTrace.configurationRefs['disambiguation'] = 'settings.disambiguation';
    86→        break;
    87→
    88→      case 'multiLabelSelection':
    89→        result.explainabilityTrace.multiLabelSelection = stageData as MultiLabelResult[];
    90→        result.explainabilityTrace.configurationRefs['multiLabelSelection'] = 'settings.multiLabelSelection';
    91→        break;
    92→
    93→      case 'aiPipeline':
    94→        result.explainabilityTrace.aiRouting = stageData as AIRoutingResult;
    95→        result.explainabilityTrace.configurationRefs['aiPipeline'] = 'ai';
    96→        break;
    97→
    98→      case 'actionDetermination':
    99→        // Action determination results are stored in result.finalClassificationSummary
   100→        // and result.determinedActions, not in explainabilityTrace
   101→        break;
   102→
   103→      default: {
   104→        // TypeScript exhaustiveness check
   105→        const _exhaustive: never = stageName;
   106→        throw new Error(`Unknown stage name: ${_exhaustive}`);
   107→      }
   108→    }
   109→
   110→    // Record stage timing if available
   111→    const timing = this.extractStageTiming(stageName, result);
   112→    if (timing !== undefined) {
   113→      result.explainabilityTrace.stageTimings[stageName] = timing;
   114→    }
   115→
   116→    // Validate stage result structure
   117→    this.validateStageResult(stageName, stageData);
   118→  }
   119→
   120→  /**
   121→   * Finalize the explainability trace after all stages complete
   122→   *
   123→   * Called by pipeline after ALL 9 stages complete successfully.
   124→   * Validates completeness and aggregates final summary fields.
   125→   *
   126→   * @param result - Classification result with all stages recorded
   127→   * @param session - Classification session context
   128→   * @throws {Error} If required stages are missing
   129→   */
   130→  finalize(result: ClassificationResult, _session: ClassificationSession): void {
   131→    // Validate all required stages are present
   132→    this.validateTraceCompleteness(result);
   133→
   134→    // Generate final decision reason from all stages
   135→    result.explainabilityTrace.finalDecisionReason = this.synthesizeFinalReason(result);
   136→
   137→    // Calculate total processing duration from stage timings
   138→    const totalDurationMs = Object.values(result.explainabilityTrace.stageTimings).reduce(
   139→      (sum, timing) => sum + timing,
   140→      0
   141→    );
   142→
   143→    // Store in explainability trace (though it's also on result.processingDurationMs)
   144→    if (totalDurationMs > 0) {
   145→      // Only update if we have valid timings
   146→      result.processingDurationMs = totalDurationMs;
   147→    }
   148→
   149→    // Aggregate alternative categories from multi-label selection
   150→    result.explainabilityTrace.alternativeCategories = this.aggregateAlternatives(result);
   151→  }
   152→
   153→  /**
   154→   * Record failure context if pipeline crashes mid-execution
   155→   *
   156→   * Called by pipeline if ANY stage crashes.
   157→   * Adds failure context to partial trace for debugging.
   158→   *
   159→   * @param result - Classification result with partial trace
   160→   * @param session - Classification session context
   161→   * @param error - Error that caused the failure
   162→   */
   163→  recordFailure(result: ClassificationResult, session: ClassificationSession, error: Error): void {
   164→    // Mark trace as partial
   165→    const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
   166→    trace.partialResults = true;
   167→
   168→    // Detect which stage failed based on what's present
   169→    trace.failedStage = this.detectFailedStage(result);
   170→
   171→    // Add error context
   172→    trace.errorMessage = error.message;
   173→    trace.errorStack = error.stack;
   174→  }
   175→
   176→  /**
   177→   * Extract stage-specific data from result object
   178→   *
   179→   * @param stageName - Stage to extract data from
   180→   * @param result - Classification result
   181→   * @returns Stage-specific data
   182→   */
   183→  private extractStageData(
   184→    stageName: StageName,
   185→    result: ClassificationResult
   186→  ):
   187→    | HardAssertionResult[]
   188→    | StrongIndicatorResult[]
   189→    | CategoryRuleResult[]
   190→    | AttributeDetectionResult[]
   191→    | AttributeInfluenceResult[]
   192→    | DisambiguationResult[]
   193→    | MultiLabelResult[]
   194→    | AIRoutingResult
   195→    | unknown {
   196→    // For now, stages still populate explainabilityTrace directly
   197→    // This method will be fully implemented when we remove direct mutations (Phase 3 of refactoring)
   198→    switch (stageName) {
   199→      case 'hardAssertions':
   200→        return result.explainabilityTrace.hardAssertions || [];
   201→      case 'strongIndicators':
   202→        return result.explainabilityTrace.strongIndicators || [];
   203→      case 'ruleScoring':
   204→        return result.explainabilityTrace.ruleScoring || [];
   205→      case 'attributeDetection':
   206→        return result.explainabilityTrace.attributeDetection || [];
   207→      case 'attributeInfluence':
   208→        return result.explainabilityTrace.attributeInfluence || [];
   209→      case 'disambiguation':
   210→        return result.explainabilityTrace.disambiguation || [];
   211→      case 'multiLabelSelection':
   212→        return result.explainabilityTrace.multiLabelSelection || [];
   213→      case 'aiPipeline':
   214→        return result.explainabilityTrace.aiRouting;
   215→      case 'actionDetermination':
   216→        return {};
   217→      default: {
   218→        const _exhaustive: never = stageName;
   219→        throw new Error(`Unknown stage name: ${_exhaustive}`);
   220→      }
   221→    }
   222→  }
   223→
   224→  /**
   225→   * Extract stage timing from result
   226→   *
   227→   * @param stageName - Stage to get timing for
   228→   * @param result - Classification result
   229→   * @returns Duration in milliseconds, or undefined if not recorded
   230→   */
   231→  private extractStageTiming(stageName: StageName, result: ClassificationResult): number | undefined {
   232→    return result.explainabilityTrace.stageTimings[stageName];
   233→  }
   234→
   235→  /**
   236→   * Validate stage result structure
   237→   *
   238→   * @param stageName - Stage that was recorded
   239→   * @param stageData - Data to validate
   240→   * @throws {Error} If stage data is malformed
   241→   */
   242→  private validateStageResult(stageName: StageName, stageData: unknown): void {
   243→    // AI pipeline can be undefined if AI stages were skipped
   244→    if (stageName === 'aiPipeline') {
   245→      // AI routing is optional
   246→      return;
   247→    }
   248→
   249→    // Basic validation - can be expanded with Zod schemas if needed
   250→    if (stageData === undefined || stageData === null) {
   251→      throw new Error(`Stage ${stageName} produced undefined/null data`);
   252→    }
   253→
   254→    // Array stages should return arrays
   255→    const arrayStages: StageName[] = [
   256→      'hardAssertions',
   257→      'strongIndicators',
   258→      'ruleScoring',
   259→      'attributeDetection',
   260→      'attributeInfluence',
   261→      'disambiguation',
   262→      'multiLabelSelection',
   263→    ];
   264→
   265→    if (arrayStages.includes(stageName) && !Array.isArray(stageData)) {
   266→      throw new Error(`Stage ${stageName} should return array, got ${typeof stageData}`);
   267→    }
   268→  }
   269→
   270→  /**
   271→   * Validate that all required stages are present in the trace
   272→   *
   273→   * @param result - Classification result to validate
   274→   * @throws {Error} If required stages are missing
   275→   */
   276→  private validateTraceCompleteness(result: ClassificationResult): void {
   277→    const requiredStages: StageName[] = [
   278→      'hardAssertions',
   279→      'strongIndicators',
   280→      'ruleScoring',
   281→      'attributeDetection',
   282→      'attributeInfluence',
   283→      'disambiguation',
   284→      'multiLabelSelection',
   285→      'aiPipeline',
   286→      'actionDetermination',
   287→    ];
   288→
   289→    const trace = result.explainabilityTrace;
   290→    const missingStages: string[] = [];
   291→
   292→    // Check each required stage
   293→    for (const stage of requiredStages) {
   294→      switch (stage) {
   295→        case 'hardAssertions':
   296→          if (!trace.hardAssertions || trace.hardAssertions.length === 0) {
   297→            // Hard assertions can be empty if no matches, but should exist
   298→            if (!trace.hardAssertions) missingStages.push(stage);
   299→          }
   300→          break;
   301→        case 'strongIndicators':
   302→          if (!trace.strongIndicators) missingStages.push(stage);
   303→          break;
   304→        case 'ruleScoring':
   305→          if (!trace.ruleScoring) missingStages.push(stage);
   306→          break;
   307→        case 'attributeDetection':
   308→          if (!trace.attributeDetection) missingStages.push(stage);
   309→          break;
   310→        case 'attributeInfluence':
   311→          if (!trace.attributeInfluence) missingStages.push(stage);
   312→          break;
   313→        case 'disambiguation':
   314→          if (!trace.disambiguation) missingStages.push(stage);
   315→          break;
   316→        case 'multiLabelSelection':
   317→          if (!trace.multiLabelSelection) missingStages.push(stage);
   318→          break;
   319→        case 'aiPipeline':
   320→          // AI pipeline is optional - only required if AI classification was used
   321→          if (result.aiRoutingUsed && !trace.aiRouting) {
   322→            missingStages.push(stage);
   323→          }
   324→          break;
   325→        case 'actionDetermination':
   326→          // Action determination results are in result.finalClassificationSummary
   327→          // During transition, this might not be set yet, so we'll be lenient
   328→          // The stage itself will have run, just might not have populated this field yet
   329→          break;
   330→      }
   331→    }
   332→
   333→    if (missingStages.length > 0) {
   334→      throw new Error(`Incomplete audit trail: missing stages ${missingStages.join(', ')}`);
   335→    }
   336→  }
   337→
   338→  /**
   339→   * Synthesize final decision reason from all stage results
   340→   *
   341→   * @param result - Classification result with all stages
   342→   * @returns Human-readable summary of classification decision
   343→   */
   344→  private synthesizeFinalReason(result: ClassificationResult): string {
   345→    const reasons: string[] = [];
   346→
   347→    // Use finalClassificationSummary if available (from action determination stage)
   348→    if (result.finalClassificationSummary) {
   349→      const summary = result.finalClassificationSummary;
   350→      reasons.push(
   351→        `Primary Category: ${summary.primaryCategory}${summary.primarySubtype ? ` (${summary.primarySubtype})` : ''}`
   352→      );
   353→      reasons.push(`Confidence: ${(summary.confidenceRange[1] * 100).toFixed(1)}%`);
   354→      reasons.push(`Classification Path: ${summary.classificationPath}`);
   355→
   356→      if (summary.selectedLabels.length > 1) {
   357→        reasons.push(`Multi-label: ${summary.selectedLabels.length} categories selected`);
   358→      }
   359→
   360→      if (summary.determinedActions.length > 0) {
   361→        reasons.push(`Actions: ${summary.determinedActions.join(', ')}`);
   362→      }
   363→    } else {
   364→      // Fallback if finalClassificationSummary not available
   365→      reasons.push(`Primary Category: ${result.primaryCategory}`);
   366→      reasons.push(`Confidence: ${(result.confidence * 100).toFixed(1)}%`);
   367→    }
   368→
   369→    // Add stage-specific insights
   370→    if (result.explainabilityTrace.hardAssertions.length > 0) {
   371→      reasons.push(`Hard Assertion: ${result.explainabilityTrace.hardAssertions[0].reason || 'Domain-based match'}`);
   372→    }
   373→
   374→    if (result.explainabilityTrace.aiRouting) {
   375→      const aiResult = result.explainabilityTrace.aiRouting;
   376→      reasons.push(`AI Routing: ${aiResult.routingDecision}`);
   377→    }
   378→
   379→    return reasons.join(' | ');
   380→  }
   381→
   382→  /**
   383→   * Aggregate alternative categories from multi-label selection
   384→   *
   385→   * @param result - Classification result
   386→   * @returns Array of alternative categories with elimination reasons
   387→   */
   388→  private aggregateAlternatives(
   389→    result: ClassificationResult
   390→  ): Array<{ category: string; score: number; eliminationReason: string }> {
   391→    const alternatives: Array<{ category: string; score: number; eliminationReason: string }> = [];
   392→
   393→    // Extract from multi-label selection results
   394→    if (result.explainabilityTrace.multiLabelSelection && result.explainabilityTrace.multiLabelSelection.length > 0) {
   395→      const multiLabel = result.explainabilityTrace.multiLabelSelection[0];
   396→      if (multiLabel.rejectedCategories) {
   397→        alternatives.push(
   398→          ...multiLabel.rejectedCategories.map((r) => ({
   399→            category: r.category,
   400→            score: r.score,
   401→            eliminationReason: r.rejectionReason,
   402→          }))
   403→        );
   404→      }
   405→    }
   406→
   407→    // Also include candidates from candidateScores that weren't selected
   408→    if (result.candidateScores) {
   409→      const selectedCategories = new Set(result.selectedLabels.map((l) => l.category));
   410→      for (const [category, scoreInfo] of Object.entries(result.candidateScores)) {
   411→        if (!selectedCategories.has(category) && scoreInfo.decision === 'rejected') {
   412→          alternatives.push({
   413→            category,
   414→            score: scoreInfo.score,
   415→            eliminationReason: scoreInfo.rationale || 'Below confidence threshold',
   416→          });
   417→        }
   418→      }
   419→    }
   420→
   421→    // Deduplicate by category (prefer multi-label rejection reasons)
   422→    const seen = new Set<string>();
   423→    return alternatives.filter((alt) => {
   424→      if (seen.has(alt.category)) return false;
   425→      seen.add(alt.category);
   426→      return true;
   427→    });
   428→  }
   429→
   430→  /**
   431→   * Detect which stage failed based on what stages are present
   432→   *
   433→   * @param result - Classification result with partial trace
   434→   * @returns Name of the stage that likely failed
   435→   */
   436→  private detectFailedStage(result: ClassificationResult): string {
   437→    const trace = result.explainabilityTrace;
   438→    const completedStages: string[] = [];
   439→
   440→    // Check which stages have been recorded
   441→    if (trace.hardAssertions) completedStages.push('hardAssertions');
   442→    if (trace.strongIndicators) completedStages.push('strongIndicators');
   443→    if (trace.ruleScoring) completedStages.push('ruleScoring');
   444→    if (trace.attributeDetection) completedStages.push('attributeDetection');
   445→    if (trace.attributeInfluence) completedStages.push('attributeInfluence');
   446→    if (trace.disambiguation) completedStages.push('disambiguation');
   447→    if (trace.multiLabelSelection) completedStages.push('multiLabelSelection');
   448→    if (trace.aiRouting) completedStages.push('aiPipeline');
   449→    if (result.finalClassificationSummary) completedStages.push('actionDetermination');
   450→
   451→    // The failed stage is the next one after the last completed
   452→    if (completedStages.length === 0) {
   453→      return 'hardAssertions (initialization failure)';
   454→    }
   455→
   456→    const lastCompleted = completedStages[completedStages.length - 1];
   457→    const lastIndex = PIPELINE_STAGE_ORDER.findIndex((s) => s === lastCompleted);
   458→
   459→    if (lastIndex === -1 || lastIndex === PIPELINE_STAGE_ORDER.length - 1) {
   460→      return `${lastCompleted} (or post-processing)`;
   461→    }
   462→
   463→    return PIPELINE_STAGE_ORDER[lastIndex + 1];
   464→  }
   465→}
   466→

