/**
 * Detect which stage failed based on what stages are present
 *
 * @param result - Classification result with partial trace
 * @returns Name of the stage that likely failed
 */
private detectFailedStage(result: ClassificationResult): string {
  const trace = result.explainabilityTrace;
  const completedStages: string[] = [];

  // Check which stages have been recorded
  if (trace.hardAssertions) completedStages.push('hardAssertions');
  if (trace.strongIndicators) completedStages.push('strongIndicators');
  if (trace.ruleScoring) completedStages.push('ruleScoring');
  if (trace.attributeDetection) completedStages.push('attributeDetection');
  if (trace.attributeInfluence) completedStages.push('attributeInfluence');
  if (trace.disambiguation) completedStages.push('disambiguation');
  if (trace.multiLabelSelection) completedStages.push('multiLabelSelection');
  if (trace.aiRouting) completedStages.push('aiPipeline');
  if (result.finalClassificationSummary) completedStages.push('actionDetermination');

  // The failed stage is the next one after the last completed
  if (completedStages.length === 0) {
    return 'hardAssertions (initialization failure)';
  }

  const lastCompleted = completedStages[completedStages.length - 1];
  const lastIndex = PIPELINE_STAGE_ORDER.findIndex((s) => s === lastCompleted);

  if (lastIndex === -1 || lastIndex === PIPELINE_STAGE_ORDER.length - 1) {
    return `${lastCompleted} (or post-processing)`;
  }

  return PIPELINE_STAGE_ORDER[lastIndex + 1];
}

