/**
 * Detect which stage failed based on what stages are present
 *
 * Uses configurationRefs to determine which stages have been recorded
 * (more reliable than checking trace fields which may be empty arrays).
 *
 * @param result - Classification result with partial trace
 * @returns Name of the stage that likely failed
 */
private detectFailedStage(result: ClassificationResult): string {
  const trace = result.explainabilityTrace;

  // Check which stages have been recorded using configurationRefs
  // (stages call recordStage which adds configurationRefs entries)
  const recordedStages = new Set<string>();

  // Check configurationRefs for recorded stages
  if (trace.configurationRefs['hardAssertions']) recordedStages.add('hardAssertions');
  if (trace.configurationRefs['strongIndicators']) recordedStages.add('strongIndicators');
  if (trace.configurationRefs['ruleScoring']) recordedStages.add('ruleScoring');
  if (trace.configurationRefs['attributeDetection']) recordedStages.add('attributeDetection');
  if (trace.configurationRefs['attributeInfluence']) recordedStages.add('attributeInfluence');
  if (trace.configurationRefs['disambiguation']) recordedStages.add('disambiguation');
  if (trace.configurationRefs['multiLabelSelection']) recordedStages.add('multiLabelSelection');
  if (trace.configurationRefs['aiPipeline']) recordedStages.add('aiPipeline');

  // Action determination doesn't add to configurationRefs, check finalClassificationSummary
  if (result.finalClassificationSummary) recordedStages.add('actionDetermination');

  // Find the last completed stage in pipeline order
  let lastCompletedStage: string | null = null;
  for (const stage of PIPELINE_STAGE_ORDER) {
    if (recordedStages.has(stage)) {
      lastCompletedStage = stage;
    } else {
      // First missing stage in order is the failed stage
      return stage;
    }
  }

  // If all stages completed, must have failed in post-processing
  if (lastCompletedStage === 'actionDetermination') {
    return 'actionDetermination (or post-processing)';
  }

  // No stages recorded at all - initialization failure
  if (lastCompletedStage === null) {
    return 'hardAssertions (initialization failure)';
  }

  // Find next stage after last completed
  const lastIndex = PIPELINE_STAGE_ORDER.findIndex((s) => s === lastCompletedStage);
  if (lastIndex !== -1 && lastIndex < PIPELINE_STAGE_ORDER.length - 1) {
    return PIPELINE_STAGE_ORDER[lastIndex + 1];
  }

  return `${lastCompletedStage} (or post-processing)`;
}

