/**
 * Unit Tests for Audit Trail Failure Recovery (T091 HP-3)
 *
 * Tests validate the hybrid progressive recording approach's failure resilience:
 * - Partial trace preservation when pipeline crashes mid-execution
 * - Error context captured for debugging
 * - Stage failure detection accuracy
 * - Graceful handling of crashes at different pipeline stages
 *
 * This validates the core value proposition of the hybrid approach:
 * "If pipeline crashes at stage 5, stages 1-4 are already recorded"
 */

import { AuditTrailGenerator } from '../../src/audit-trail/audit-trail-generator';
import { ClassificationResult } from '../../src/types/classification-result';
import { ClassificationSession } from '../../src/types/classification-session';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { StageName } from '../../src/types/stage-name';
import { ExplainabilityTrace } from '../../src/types/explainability-trace';

describe('Audit Trail Failure Recovery (T091 HP-3)', () => {
  // Mock minimal config for audit trail generator
  const mockConfig: CategoryConfiguration = {
    processingConfig: {
      settings: {
        multiLabelSelection: {
          highConfidenceThreshold: 15,
          mediumConfidenceThreshold: 10,
          lowConfidenceThreshold: 5,
          secondaryLabelMinGap: 3,
        },
        disambiguation: {
          enabled: true,
          minScoreDifference: 2,
        },
      },
      categorySignals: {},
      attributes: {},
      ai: {
        enabled: true,
        providers: [],
        prompts: {},
        schemas: {},
      },
    },
    domainSources: {},
  };

  const mockSession: ClassificationSession = {
    id: 'session-test-123',
    startedAt: new Date('2025-10-20T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'sequential',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-v1',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  /**
   * Helper to create a classification result with initialized explainability trace
   */
  function createTestResult(emailId: string, sessionId: string): ClassificationResult {
    const explainabilityTrace: ExplainabilityTrace = {
      sessionId,
      emailId,
      hardAssertions: [],
      strongIndicators: [],
      ruleScoring: [],
      attributeDetection: [],
      attributeInfluence: [],
      disambiguation: [],
      multiLabelSelection: [],
      aiRouting: undefined,
      stageTimings: {},
      configurationRefs: {},
      parallelExecutionMap: {},
      alternativeCategories: [],
      finalDecisionReason: '',
    };

    return {
      emailId,
      sessionId,
      primaryCategory: null,
      secondaryCategories: [],
      confidence: 0,
      processingDurationMs: 0,
      processedAt: new Date(),
      selectedLabels: [],
      candidateScores: {},
      needsAiClassification: false,
      aiRoutingUsed: false,
      explainabilityTrace,
      determinedActions: [],
      finalClassificationSummary: undefined,
    };
  }

  describe('Progressive Recording Resilience', () => {
    it('should preserve partial trace when pipeline fails after stage 1 (hardAssertions)', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-123', mockSession.id);

      // Simulate stage 1 completing successfully
      result.explainabilityTrace.hardAssertions = [
        {
          category: 'financial',
          assertionType: 'fromDomain',
          matchedValue: 'chase.com',
          confidence: 'HIGH_CONFIDENCE',
          triggered: true,
          reason: 'Domain matched hard assertion',
        },
      ];
      result.explainabilityTrace.stageTimings.hardAssertions = 5;

      // Record stage 1
      generator.recordStage('hardAssertions', result, mockSession);

      // Simulate pipeline crash before stage 2
      const error = new Error('Network timeout in stage 2');
      generator.recordFailure(result, mockSession, error);

      // Verify partial trace preserved
      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.hardAssertions[0].category).toBe('financial');

      // Verify error context captured
      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.partialResults).toBe(true);
      expect(trace.errorMessage).toBe('Network timeout in stage 2');
      expect(trace.errorStack).toBeDefined();
      expect(trace.failedStage).toContain('strongIndicators');
    });

    it('should preserve partial trace when pipeline fails after stage 4 (attributeDetection)', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-456', mockSession.id);

      // Simulate stages 1-4 completing successfully
      result.explainabilityTrace.hardAssertions = [];
      result.explainabilityTrace.stageTimings.hardAssertions = 5;
      generator.recordStage('hardAssertions', result, mockSession);

      result.explainabilityTrace.strongIndicators = [
        {
          category: 'financial',
          indicatorType: 'subjectContains',
          matchedValue: 'invoice',
          seedScore: 10,
          diminishingReturnsApplied: false,
          existingSeedScore: 0,
          finalSeedScore: 10,
          reason: 'Subject keyword match',
        },
      ];
      result.explainabilityTrace.stageTimings.strongIndicators = 8;
      generator.recordStage('strongIndicators', result, mockSession);

      result.explainabilityTrace.ruleScoring = [
        {
          category: 'financial',
          subtype: 'invoice',
          tier: 'high',
          matchedRules: [],
          rawScore: 12,
          cappedScore: 12,
          tierWeight: 1.0,
          reason: 'High tier rule match',
        },
      ];
      result.explainabilityTrace.stageTimings.ruleScoring = 45;
      generator.recordStage('ruleScoring', result, mockSession);

      result.explainabilityTrace.attributeDetection = [
        {
          attribute: 'hasAmount',
          detected: true,
          detectionMethod: 'regex',
          sourceField: 'body',
          confidence: 0.95,
          parallelProcessed: false,
          dependencies: [],
          reason: 'Amount pattern detected',
        },
      ];
      result.explainabilityTrace.stageTimings.attributeDetection = 20;
      generator.recordStage('attributeDetection', result, mockSession);

      // Simulate pipeline crash before stage 5
      const error = new Error('OOM error in attribute influence stage');
      generator.recordFailure(result, mockSession, error);

      // Verify stages 1-4 preserved
      expect(result.explainabilityTrace.hardAssertions).toEqual([]);
      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.explainabilityTrace.ruleScoring).toHaveLength(1);
      expect(result.explainabilityTrace.attributeDetection).toHaveLength(1);

      // Verify stage 5+ not present
      expect(result.explainabilityTrace.attributeInfluence).toEqual([]);
      expect(result.explainabilityTrace.disambiguation).toEqual([]);

      // Verify error context and failed stage detection
      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.partialResults).toBe(true);
      expect(trace.errorMessage).toContain('OOM error');
      expect(trace.failedStage).toContain('attributeInfluence');
    });

    it('should preserve partial trace when pipeline fails after stage 7 (multiLabelSelection)', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-789', mockSession.id);

      // Simulate stages 1-7 completing successfully
      const stages: StageName[] = [
        'hardAssertions',
        'strongIndicators',
        'ruleScoring',
        'attributeDetection',
        'attributeInfluence',
        'disambiguation',
        'multiLabelSelection',
      ];

      for (const stage of stages) {
        // Set mock data based on stage
        switch (stage) {
          case 'hardAssertions':
            result.explainabilityTrace.hardAssertions = [];
            break;
          case 'strongIndicators':
            result.explainabilityTrace.strongIndicators = [];
            break;
          case 'ruleScoring':
            result.explainabilityTrace.ruleScoring = [];
            break;
          case 'attributeDetection':
            result.explainabilityTrace.attributeDetection = [];
            break;
          case 'attributeInfluence':
            result.explainabilityTrace.attributeInfluence = [];
            break;
          case 'disambiguation':
            result.explainabilityTrace.disambiguation = [];
            break;
          case 'multiLabelSelection':
            result.explainabilityTrace.multiLabelSelection = [
              {
                category: 'financial',
                subtype: 'invoice',
                confidence: 0.85,
                score: 15.2,
                isPrimary: true,
                labelOrder: 1,
                selectionRationale: 'High confidence',
                rejectedCategories: [],
              },
            ];
            break;
        }

        result.explainabilityTrace.stageTimings[stage] = 10;
        generator.recordStage(stage, result, mockSession);
      }

      // Simulate pipeline crash in AI pipeline (stage 8)
      const error = new Error('OpenAI API rate limit exceeded');
      generator.recordFailure(result, mockSession, error);

      // Verify stages 1-7 fully preserved
      expect(result.explainabilityTrace.multiLabelSelection).toHaveLength(1);
      expect(result.explainabilityTrace.stageTimings).toHaveProperty('multiLabelSelection');

      // Verify AI stages not present
      expect(result.explainabilityTrace.aiRouting).toBeUndefined();

      // Verify error context
      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.partialResults).toBe(true);
      expect(trace.errorMessage).toContain('OpenAI API rate limit');
      expect(trace.failedStage).toContain('aiPipeline');
    });
  });

  describe('Error Context Capture', () => {
    it('should capture error message, stack, and failed stage information', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-error-001', mockSession.id);

      // Record stage 1 only
      result.explainabilityTrace.hardAssertions = [];
      generator.recordStage('hardAssertions', result, mockSession);

      // Create error with stack trace
      const error = new Error('Database connection refused');
      error.stack = 'Error: Database connection refused\n  at Stage2.execute (strong-indicators.ts:45)';

      generator.recordFailure(result, mockSession, error);

      // Verify error context
      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.errorMessage).toBe('Database connection refused');
      expect(trace.errorStack).toContain('strong-indicators.ts:45');
      expect(trace.partialResults).toBe(true);
      expect(trace.failedStage).toBeDefined();
    });

    it('should handle errors without stack traces gracefully', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-error-002', mockSession.id);

      // Record a few stages
      result.explainabilityTrace.hardAssertions = [];
      generator.recordStage('hardAssertions', result, mockSession);

      result.explainabilityTrace.strongIndicators = [];
      generator.recordStage('strongIndicators', result, mockSession);

      // Create error without stack trace
      const error = new Error('Unknown error');
      error.stack = undefined;

      generator.recordFailure(result, mockSession, error);

      // Verify error context (should not crash)
      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.errorMessage).toBe('Unknown error');
      expect(trace.errorStack).toBeUndefined();
      expect(trace.partialResults).toBe(true);
    });
  });

  describe('Failed Stage Detection', () => {
    it('should correctly identify failed stage when crash happens at initialization', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-init-fail', mockSession.id);

      // No stages recorded - crash before stage 1
      const error = new Error('Configuration validation failed');
      generator.recordFailure(result, mockSession, error);

      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.failedStage).toContain('hardAssertions');
      expect(trace.failedStage).toContain('initialization failure');
    });

    it('should correctly identify failed stage between stages 2 and 3', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-stage23-fail', mockSession.id);

      // Stages 1-2 complete
      result.explainabilityTrace.hardAssertions = [];
      generator.recordStage('hardAssertions', result, mockSession);

      result.explainabilityTrace.strongIndicators = [];
      generator.recordStage('strongIndicators', result, mockSession);

      // Crash before stage 3
      const error = new Error('Rule scoring failed');
      generator.recordFailure(result, mockSession, error);

      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.failedStage).toBe('ruleScoring');
    });

    it('should correctly identify failed stage at the end of pipeline (actionDetermination)', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-final-fail', mockSession.id);

      // All stages except actionDetermination complete
      const stages: StageName[] = [
        'hardAssertions',
        'strongIndicators',
        'ruleScoring',
        'attributeDetection',
        'attributeInfluence',
        'disambiguation',
        'multiLabelSelection',
      ];

      for (const stage of stages) {
        // Initialize empty arrays for array stages
        switch (stage) {
          case 'hardAssertions':
            result.explainabilityTrace.hardAssertions = [];
            break;
          case 'strongIndicators':
            result.explainabilityTrace.strongIndicators = [];
            break;
          case 'ruleScoring':
            result.explainabilityTrace.ruleScoring = [];
            break;
          case 'attributeDetection':
            result.explainabilityTrace.attributeDetection = [];
            break;
          case 'attributeInfluence':
            result.explainabilityTrace.attributeInfluence = [];
            break;
          case 'disambiguation':
            result.explainabilityTrace.disambiguation = [];
            break;
          case 'multiLabelSelection':
            result.explainabilityTrace.multiLabelSelection = [];
            break;
        }
        generator.recordStage(stage, result, mockSession);
      }

      // AI pipeline completed (optional stage)
      result.explainabilityTrace.aiRouting = {
        routingDecision: 'skipAi',
        highConfidenceThreshold: 15,
        aiRequiredThreshold: 3,
        skipConditions: ['highConfidence'],
        reason: 'High confidence, AI not needed',
      };
      result.aiRoutingUsed = false;
      generator.recordStage('aiPipeline', result, mockSession);

      // Crash in actionDetermination
      const error = new Error('Action determination failed');
      generator.recordFailure(result, mockSession, error);

      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.failedStage).toBe('actionDetermination');
    });
  });

  describe('Integration with finalize()', () => {
    it('should allow finalize() to be called after recordFailure() without errors', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-finalize-after-fail', mockSession.id);

      // Record some stages
      result.explainabilityTrace.hardAssertions = [];
      generator.recordStage('hardAssertions', result, mockSession);

      result.explainabilityTrace.strongIndicators = [];
      generator.recordStage('strongIndicators', result, mockSession);

      // Record failure
      const error = new Error('Simulated failure');
      generator.recordFailure(result, mockSession, error);

      // Attempting to finalize after failure should not crash
      // (This might happen in error recovery scenarios)
      expect(() => {
        try {
          generator.finalize(result, mockSession);
        } catch (e) {
          // Finalize might throw due to missing required stages,
          // but should not crash with unhandled exceptions
          expect(e).toBeInstanceOf(Error);
        }
      }).not.toThrow();
    });

    it('should not lose partial trace data when finalize() is attempted after failure', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-preserve-after-finalize', mockSession.id);

      // Record stages 1-3
      result.explainabilityTrace.hardAssertions = [
        {
          category: 'financial',
          assertionType: 'fromDomain',
          matchedValue: 'chase.com',
          confidence: 'HIGH_CONFIDENCE',
          triggered: true,
          reason: 'Domain match',
        },
      ];
      generator.recordStage('hardAssertions', result, mockSession);

      result.explainabilityTrace.strongIndicators = [];
      generator.recordStage('strongIndicators', result, mockSession);

      result.explainabilityTrace.ruleScoring = [];
      generator.recordStage('ruleScoring', result, mockSession);

      // Record failure
      const error = new Error('Stage 4 crashed');
      generator.recordFailure(result, mockSession, error);

      // Attempt finalize (will fail due to missing stages, but partial trace should remain)
      try {
        generator.finalize(result, mockSession);
      } catch (e) {
        // Expected to throw due to incomplete trace
      }

      // Verify partial trace data still intact
      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.strongIndicators).toEqual([]);
      expect(result.explainabilityTrace.ruleScoring).toEqual([]);

      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.partialResults).toBe(true);
      expect(trace.errorMessage).toBe('Stage 4 crashed');
    });
  });

  describe('Real-World Failure Scenarios', () => {
    it('should handle memory exhaustion failure mid-pipeline', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-memory-fail', mockSession.id);

      // Stages 1-5 complete
      result.explainabilityTrace.hardAssertions = [];
      generator.recordStage('hardAssertions', result, mockSession);

      result.explainabilityTrace.strongIndicators = [];
      generator.recordStage('strongIndicators', result, mockSession);

      result.explainabilityTrace.ruleScoring = [];
      generator.recordStage('ruleScoring', result, mockSession);

      result.explainabilityTrace.attributeDetection = [];
      generator.recordStage('attributeDetection', result, mockSession);

      result.explainabilityTrace.attributeInfluence = [];
      generator.recordStage('attributeInfluence', result, mockSession);

      // Memory exhaustion in disambiguation
      const error = new Error('JavaScript heap out of memory');
      error.name = 'RangeError';
      generator.recordFailure(result, mockSession, error);

      // Verify stages 1-5 intact
      expect(result.explainabilityTrace.attributeInfluence).toEqual([]);

      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.errorMessage).toContain('heap out of memory');
      expect(trace.failedStage).toBe('disambiguation');
    });

    it('should handle external API timeout in AI pipeline', () => {
      const generator = new AuditTrailGenerator(mockConfig);
      const result = createTestResult('email-api-timeout', mockSession.id);

      // All rule-based stages complete (1-7)
      const stages: StageName[] = [
        'hardAssertions',
        'strongIndicators',
        'ruleScoring',
        'attributeDetection',
        'attributeInfluence',
        'disambiguation',
        'multiLabelSelection',
      ];

      for (const stage of stages) {
        switch (stage) {
          case 'hardAssertions':
            result.explainabilityTrace.hardAssertions = [];
            break;
          case 'strongIndicators':
            result.explainabilityTrace.strongIndicators = [];
            break;
          case 'ruleScoring':
            result.explainabilityTrace.ruleScoring = [];
            break;
          case 'attributeDetection':
            result.explainabilityTrace.attributeDetection = [];
            break;
          case 'attributeInfluence':
            result.explainabilityTrace.attributeInfluence = [];
            break;
          case 'disambiguation':
            result.explainabilityTrace.disambiguation = [];
            break;
          case 'multiLabelSelection':
            result.explainabilityTrace.multiLabelSelection = [
              {
                category: 'unknown',
                subtype: null,
                confidence: 0.45,
                score: 8.2,
                isPrimary: true,
                labelOrder: 1,
                selectionRationale: 'Low confidence, needs AI',
                rejectedCategories: [],
              },
            ];
            result.needsAiClassification = true;
            break;
        }
        generator.recordStage(stage, result, mockSession);
      }

      // OpenAI API timeout
      const error = new Error('Request timeout: OpenAI API did not respond within 30s');
      error.name = 'TimeoutError';
      generator.recordFailure(result, mockSession, error);

      // Verify rule-based stages intact (valuable for debugging why AI was needed)
      expect(result.explainabilityTrace.multiLabelSelection).toHaveLength(1);
      expect(result.needsAiClassification).toBe(true);

      const trace = result.explainabilityTrace as unknown as Record<string, unknown>;
      expect(trace.errorMessage).toContain('OpenAI API');
      expect(trace.failedStage).toContain('aiPipeline');
    });
  });
});

